import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
} from '@angular/core';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';

export type MfProgressSpinnerMode = 'determinate' | 'indeterminate';
export type MfProgressSpinnerColor = 'brand' | 'accent' | 'warn';

/**
 * Spinner de progreso de la librería mf-components.
 * Envuelve Angular Material `mat-progress-spinner` y expone una API uniforme
 * con look and feel de marca.
 */
@Component({
  selector: 'mf-progress-spinner',
  imports: [MatProgressSpinnerModule],
  template: `
    <div [class]="wrapperClasses()" [attr.aria-label]="label() || 'Cargando'">
      <mat-progress-spinner
        [class]="hostClasses()"
        [mode]="mode()"
        [value]="value()"
        [diameter]="diameter()"
        [strokeWidth]="strokeWidth()"
      />
      @if (label()) {
        <span class="mf-progress-spinner__label">{{ label() }}</span>
      }
    </div>
  `,
  styleUrl: './mf-progress-spinner.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfProgressSpinnerComponent {
  /** Modo del spinner */
  readonly mode = input<MfProgressSpinnerMode>('indeterminate');
  /** Valor actual (0–100, solo en modo determinate) */
  readonly value = input(0);
  /** Diámetro en px */
  readonly diameter = input(40);
  /** Grosor del trazo en px */
  readonly strokeWidth = input(4);
  /** Color del spinner */
  readonly color = input<MfProgressSpinnerColor>('brand');
  /** Etiqueta accesible y visible */
  readonly label = input<string | undefined>(undefined);

  readonly hostClasses = computed(() => {
    return `mf-progress-spinner mf-progress-spinner--${this.color()}`;
  });

  readonly wrapperClasses = computed(() => {
    const classes = ['mf-progress-spinner__wrapper'];
    if (this.label()) classes.push('mf-progress-spinner__wrapper--labeled');
    return classes.join(' ');
  });
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  effect,
  input,
  output,
  signal,
} from '@angular/core';
import { MatRadioModule } from '@angular/material/radio';
import { FormsModule } from '@angular/forms';

export interface MfRadioOption {
  /** Valor de la opción */
  value: string;
  /** Texto visible */
  label: string;
  /** Deshabilitada individualmente */
  disabled?: boolean;
}

export type MfRadioDirection = 'horizontal' | 'vertical';

/**
 * Grupo de radio buttons de la librería mf-components.
 * Envuelve Angular Material `mat-radio-group` + `mat-radio-button`
 * y expone una API uniforme con look and feel de marca.
 */
@Component({
  selector: 'mf-radio-button',
  imports: [MatRadioModule, FormsModule],
  template: `
    <mat-radio-group
      [class]="hostClasses()"
      [disabled]="disabled()"
      [ngModel]="currentValue()"
      (change)="onChange($event)"
      [attr.aria-label]="ariaLabel() || null"
    >
      @for (option of options(); track option.value) {
        <mat-radio-button
          class="mf-radio__option"
          [value]="option.value"
          [disabled]="option.disabled ?? false"
        >
          {{ option.label }}
        </mat-radio-button>
      }
    </mat-radio-group>
  `,
  styleUrl: './mf-radio-button.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfRadioButtonComponent {
  /** Opciones del grupo */
  readonly options = input.required<MfRadioOption[]>();
  /** Valor seleccionado */
  readonly value = input<string | undefined>(undefined);
  /** Deshabilitado */
  readonly disabled = input(false);
  /** Dirección del grupo */
  readonly direction = input<MfRadioDirection>('vertical');
  /** Etiqueta accesible para el grupo */
  readonly ariaLabel = input<string | undefined>(undefined);

  readonly mfChange = output<string>();

  protected readonly currentValue = signal<string | undefined>(undefined);

  constructor() {
    effect(() => {
      this.currentValue.set(this.value());
    });
  }

  readonly hostClasses = computed(() => {
    return `mf-radio mf-radio--${this.direction()}`;
  });

  onChange(event: { value: string }): void {
    this.currentValue.set(event.value);
    this.mfChange.emit(event.value);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import { MatSidenavModule } from '@angular/material/sidenav';

export type MfSidenavMode = 'over' | 'push' | 'side';
export type MfSidenavPosition = 'start' | 'end';

/**
 * Panel lateral de la librería mf-components.
 * Envuelve Angular Material `mat-sidenav-container` y expone una API uniforme
 * con look and feel de marca. Usa content projection para el contenido del
 * sidenav y el contenido principal.
 */
@Component({
  selector: 'mf-sidenav',
  imports: [MatSidenavModule],
  template: `
    <mat-sidenav-container [class]="containerClasses()" [hasBackdrop]="hasBackdrop()">
      <mat-sidenav
        [class]="sidenavClasses()"
        [mode]="mode()"
        [position]="position()"
        [opened]="opened()"
        [style.width]="sidenavWidth()"
        (openedChange)="mfOpenedChange.emit($event)"
      >
        <ng-content select="[mfSidenavContent]" />
      </mat-sidenav>
      <mat-sidenav-content class="mf-sidenav__main">
        <ng-content />
      </mat-sidenav-content>
    </mat-sidenav-container>
  `,
  styleUrl: './mf-sidenav.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfSidenavComponent {
  /** Abierto o cerrado */
  readonly opened = input(false);
  /** Modo de apertura */
  readonly mode = input<MfSidenavMode>('side');
  /** Posición del panel */
  readonly position = input<MfSidenavPosition>('start');
  /** Muestra backdrop al abrir */
  readonly hasBackdrop = input<boolean | null>(null);
  /** Ancho del panel lateral */
  readonly sidenavWidth = input('260px');

  readonly mfOpenedChange = output<boolean>();

  readonly containerClasses = computed(() => 'mf-sidenav-container');

  readonly sidenavClasses = computed(() => {
    return `mf-sidenav mf-sidenav--${this.mode()}`;
  });
}

